CREATE SCHEMA IF NOT EXISTS project;

CREATE OR REPLACE FUNCTION project._avancement_global(p_chantier_id integer)
 RETURNS numeric
 LANGUAGE sql
 STABLE
AS $function$
  SELECT COALESCE(ROUND(AVG(pct_avancement), 1), 0)
  FROM project.jalon
  WHERE chantier_id = p_chantier_id;
$function$;
COMMENT ON FUNCTION project._avancement_global(integer) IS 'Calculate global progress % from milestones';

CREATE OR REPLACE FUNCTION project._client_options()
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_html text := '';
  r record;
BEGIN
  FOR r IN SELECT id, name FROM crm.client WHERE active ORDER BY name LOOP
    v_html := v_html || '<option value="' || r.id || '">' || pgv.esc(r.name) || '</option>';
  END LOOP;
  RETURN v_html;
END;
$function$;
COMMENT ON FUNCTION project._client_options() IS 'Options HTML des clients actifs pour les selects';

CREATE OR REPLACE FUNCTION project._devis_options(p_client_id integer DEFAULT NULL::integer)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_html text := '';
  r record;
BEGIN
  FOR r IN
    SELECT d.id, d.numero, d.objet
      FROM quote.devis d
     WHERE d.statut = 'accepte'
       AND (p_client_id IS NULL OR d.client_id = p_client_id)
     ORDER BY d.created_at DESC
  LOOP
    v_html := v_html || '<option value="' || r.id || '">' || pgv.esc(r.numero || ' — ' || r.objet) || '</option>';
  END LOOP;
  RETURN v_html;
END;
$function$;
COMMENT ON FUNCTION project._devis_options(integer) IS 'Options HTML des devis acceptes d''un client';

CREATE OR REPLACE FUNCTION project._chantier_form_fields(p_id integer DEFAULT NULL::integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_body text := '';
  v_objet text := '';
  v_adresse text := '';
  v_notes text := '';
  v_date_debut text := '';
  v_date_fin text := '';
  v_client_id int;
  v_devis_id int;
BEGIN
  IF p_id IS NOT NULL THEN
    SELECT objet, adresse, notes, date_debut::text, date_fin_prevue::text, client_id, devis_id
      INTO v_objet, v_adresse, v_notes, v_date_debut, v_date_fin, v_client_id, v_devis_id
      FROM project.chantier WHERE id = p_id;
    IF NOT FOUND THEN RETURN pgv.empty(pgv.t('project.empty_introuvable')); END IF;
    v_body := '<input type="hidden" name="id" value="' || p_id || '">';
    v_objet := pgv.esc(v_objet);
    v_adresse := pgv.esc(COALESCE(v_adresse, ''));
    v_notes := pgv.esc(COALESCE(v_notes, ''));
    v_date_debut := COALESCE(v_date_debut, '');
    v_date_fin := COALESCE(v_date_fin, '');
  END IF;

  v_body := v_body
    || '<label>' || pgv.t('project.field_client') || ' <select name="client_id" required>'
    || '<option value="">' || pgv.t('project.field_choisir') || '</option>'
    || project._client_options()
    || '</select></label>';

  IF v_client_id IS NOT NULL THEN
    v_body := replace(v_body,
      'value="' || v_client_id || '">',
      'value="' || v_client_id || '" selected>');
  END IF;

  v_body := v_body
    || '<label>' || pgv.t('project.field_devis') || ' <select name="devis_id">'
    || '<option value="">' || pgv.t('project.field_aucun') || '</option>'
    || project._devis_options()
    || '</select></label>';

  IF v_devis_id IS NOT NULL THEN
    v_body := replace(v_body,
      'value="' || v_devis_id || '">',
      'value="' || v_devis_id || '" selected>');
  END IF;

  v_body := v_body
    || pgv.input('objet', 'text', pgv.t('project.field_objet'), v_objet, true)
    || pgv.input('adresse', 'text', pgv.t('project.field_adresse'), v_adresse)
    || '<div class="grid">'
    || pgv.input('date_debut', 'date', pgv.t('project.field_date_debut'), NULLIF(v_date_debut, ''))
    || pgv.input('date_fin_prevue', 'date', pgv.t('project.field_date_fin_prevue'), NULLIF(v_date_fin, ''))
    || '</div>'
    || pgv.textarea('notes', pgv.t('project.field_notes'), v_notes);

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION project._chantier_form_fields(integer) IS 'Returns form fields HTML for chantier create/edit (used by form_dialog). No form wrapper.';

CREATE OR REPLACE FUNCTION project._next_numero()
 RETURNS text
 LANGUAGE sql
 STABLE
AS $function$
  SELECT 'CHT-' || to_char(now(), 'YYYY') || '-' ||
         lpad((COALESCE(
           (SELECT MAX(substring(numero FROM '\d+$')::int)
            FROM project.chantier
            WHERE numero LIKE 'CHT-' || to_char(now(), 'YYYY') || '-%'),
           0) + 1)::text, 3, '0');
$function$;
COMMENT ON FUNCTION project._next_numero() IS 'Generate next chantier number CHT-YYYY-NNN';

CREATE OR REPLACE FUNCTION project._statut_badge(p_statut text)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
BEGIN
  RETURN pgv.badge(
    CASE p_statut
      WHEN 'preparation' THEN pgv.t('project.statut_preparation')
      WHEN 'execution'   THEN pgv.t('project.statut_execution')
      WHEN 'reception'   THEN pgv.t('project.statut_reception')
      WHEN 'clos'        THEN pgv.t('project.statut_clos')
      ELSE initcap(p_statut)
    END,
    CASE p_statut
      WHEN 'preparation' THEN 'warning'
      WHEN 'execution'   THEN 'info'
      WHEN 'reception'   THEN 'success'
      WHEN 'clos'        THEN 'default'
    END
  );
END;
$function$;
COMMENT ON FUNCTION project._statut_badge(text) IS 'Badge coloré pour un statut de chantier';

CREATE OR REPLACE FUNCTION project.brand()
 RETURNS text
 LANGUAGE sql
 STABLE
AS $function$
  SELECT pgv.t('project.brand');
$function$;
COMMENT ON FUNCTION project.brand() IS 'Brand name for Project module';

CREATE OR REPLACE FUNCTION project.chantier_create(p_row project.chantier)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_result jsonb;
BEGIN
  p_row.tenant_id := current_setting('app.tenant_id', true);
  p_row.numero := project._next_numero();
  p_row.statut := COALESCE(NULLIF(p_row.statut, ''), 'preparation');
  p_row.created_at := now();
  p_row.updated_at := now();

  INSERT INTO project.chantier (numero, client_id, devis_id, objet, adresse, statut,
    date_debut, date_fin_prevue, notes, created_at, updated_at, tenant_id)
  VALUES (p_row.numero, p_row.client_id, p_row.devis_id, p_row.objet, p_row.adresse, p_row.statut,
    p_row.date_debut, p_row.date_fin_prevue, p_row.notes, p_row.created_at, p_row.updated_at, p_row.tenant_id)
  RETURNING to_jsonb(project.chantier.*) INTO v_result;

  RETURN v_result;
END;
$function$;
COMMENT ON FUNCTION project.chantier_create(project.chantier) IS 'Create chantier — auto-generates numero, sets tenant_id and timestamps';

CREATE OR REPLACE FUNCTION project.chantier_delete(p_id text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_result jsonb;
BEGIN
  DELETE FROM project.chantier
  WHERE id = p_id::int AND tenant_id = current_setting('app.tenant_id', true)
  RETURNING to_jsonb(project.chantier.*) INTO v_result;

  RETURN v_result;
END;
$function$;
COMMENT ON FUNCTION project.chantier_delete(text) IS 'Delete chantier by id — returns deleted row as jsonb or NULL';

CREATE OR REPLACE FUNCTION project.chantier_list(p_filter text DEFAULT NULL::text)
 RETURNS SETOF jsonb
 LANGUAGE plpgsql
 STABLE
AS $function$
BEGIN
  IF p_filter IS NULL THEN
    RETURN QUERY
      SELECT to_jsonb(c) || jsonb_build_object(
        'client_name', cl.name,
        'devis_numero', d.numero,
        'avancement', project._avancement_global(c.id)
      )
      FROM project.chantier c
      JOIN crm.client cl ON cl.id = c.client_id
      LEFT JOIN quote.devis d ON d.id = c.devis_id
      WHERE c.tenant_id = current_setting('app.tenant_id', true)
      ORDER BY c.updated_at DESC;
  ELSE
    RETURN QUERY EXECUTE
      'SELECT to_jsonb(c) || jsonb_build_object(
        ''client_name'', cl.name,
        ''devis_numero'', d.numero,
        ''avancement'', project._avancement_global(c.id)
      )
      FROM project.chantier c
      JOIN crm.client cl ON cl.id = c.client_id
      LEFT JOIN quote.devis d ON d.id = c.devis_id
      WHERE c.tenant_id = ' || quote_literal(current_setting('app.tenant_id', true))
      || ' AND ' || pgv.rsql_to_where(p_filter, 'project', 'chantier')
      || ' ORDER BY c.updated_at DESC';
  END IF;
END;
$function$;
COMMENT ON FUNCTION project.chantier_list(text) IS 'List chantiers for current tenant with client name and devis numero resolved — optional RSQL filter';

CREATE OR REPLACE FUNCTION project.chantier_options(p_search text DEFAULT ''::text)
 RETURNS TABLE(value text, label text, detail text)
 LANGUAGE plpgsql
 STABLE
AS $function$
BEGIN
  RETURN QUERY
    SELECT c.id::text,
           c.numero || ' — ' || pgv.esc(c.objet),
           project._statut_badge(c.statut)
      FROM project.chantier c
     WHERE p_search = ''
        OR c.numero ILIKE '%' || p_search || '%'
        OR c.objet  ILIKE '%' || p_search || '%'
     ORDER BY c.updated_at DESC NULLS LAST
     LIMIT 20;
END;
$function$;
COMMENT ON FUNCTION project.chantier_options(text) IS 'Recherche chantiers pour pgv.select_search() — retourne value/label/detail';

CREATE OR REPLACE FUNCTION project.chantier_read(p_id text)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_row jsonb;
  v_statut text;
  v_actions jsonb := '[]'::jsonb;
  v_uri text;
BEGIN
  SELECT to_jsonb(c) || jsonb_build_object(
    'client_name', cl.name,
    'devis_numero', d.numero,
    'avancement', project._avancement_global(c.id),
    'heures_total', (SELECT COALESCE(sum(heures), 0) FROM project.pointage WHERE chantier_id = c.id),
    'jalons_count', (SELECT count(*) FROM project.jalon WHERE chantier_id = c.id)
  ) INTO v_row
  FROM project.chantier c
  JOIN crm.client cl ON cl.id = c.client_id
  LEFT JOIN quote.devis d ON d.id = c.devis_id
  WHERE c.id = p_id::int AND c.tenant_id = current_setting('app.tenant_id', true);

  IF v_row IS NULL THEN RETURN NULL; END IF;

  v_statut := v_row ->> 'statut';
  v_uri := 'project://chantier/' || p_id;

  CASE v_statut
    WHEN 'preparation' THEN
      v_actions := jsonb_build_array(
        jsonb_build_object('method', 'demarrer', 'uri', v_uri || '/demarrer'),
        jsonb_build_object('method', 'edit', 'uri', v_uri),
        jsonb_build_object('method', 'supprimer', 'uri', v_uri || '/supprimer')
      );
    WHEN 'execution' THEN
      v_actions := jsonb_build_array(
        jsonb_build_object('method', 'reception', 'uri', v_uri || '/reception'),
        jsonb_build_object('method', 'edit', 'uri', v_uri)
      );
    WHEN 'reception' THEN
      v_actions := jsonb_build_array(
        jsonb_build_object('method', 'clore', 'uri', v_uri || '/clore')
      );
    ELSE
      v_actions := '[]'::jsonb;
  END CASE;

  v_row := v_row || jsonb_build_object('actions', v_actions);
  RETURN v_row;
END;
$function$;
COMMENT ON FUNCTION project.chantier_read(text) IS 'Read chantier by id — returns enriched jsonb with client name and devis numero';

CREATE OR REPLACE FUNCTION project.chantier_ui(p_slug text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_row jsonb;
  v_numero text;
  v_objet text;
  v_client text;
  v_statut text;
  v_avancement text;
  v_adresse text;
  v_devis text;
  v_debut text;
  v_fin text;
  v_notes text;
BEGIN
  -- List mode
  IF p_slug IS NULL THEN
    RETURN jsonb_build_object(
      'ui', pgv.ui_column(
        pgv.ui_heading(pgv.t('project.nav_projets')),
        pgv.ui_table('chantiers', jsonb_build_array(
          pgv.ui_col('numero', pgv.t('project.col_numero'), pgv.ui_link('{numero}', '/project/chantier/{id}')),
          pgv.ui_col('client_name', pgv.t('project.col_client')),
          pgv.ui_col('objet', pgv.t('project.col_objet')),
          pgv.ui_col('statut', pgv.t('project.col_statut'), pgv.ui_badge('{statut}')),
          pgv.ui_col('avancement', pgv.t('project.col_avancement')),
          pgv.ui_col('devis_numero', pgv.t('project.col_devis')),
          pgv.ui_col('date_debut', pgv.t('project.col_debut'))
        ))
      ),
      'datasources', jsonb_build_object(
        'chantiers', pgv.ui_datasource('project://chantier', 20, true, 'updated_at')
      )
    );
  END IF;

  -- Detail mode
  v_row := project.chantier_read(p_slug);
  IF v_row IS NULL THEN
    RETURN jsonb_build_object('error', 'not_found');
  END IF;

  v_numero := v_row ->> 'numero';
  v_objet := v_row ->> 'objet';
  v_client := v_row ->> 'client_name';
  v_statut := v_row ->> 'statut';
  v_avancement := v_row ->> 'avancement';
  v_adresse := COALESCE(v_row ->> 'adresse', '—');
  v_devis := COALESCE(v_row ->> 'devis_numero', '—');
  v_debut := COALESCE(v_row ->> 'date_debut', '—');
  v_fin := COALESCE(v_row ->> 'date_fin_prevue', '—');
  v_notes := COALESCE(NULLIF(v_row ->> 'notes', ''), '—');

  RETURN jsonb_build_object(
    'ui', pgv.ui_column(
      pgv.ui_row(
        pgv.ui_link('← ' || pgv.t('project.nav_projets'), '/project/chantiers'),
        pgv.ui_heading(v_numero || ' — ' || v_objet)
      ),
      pgv.ui_heading(pgv.t('project.title_informations'), 3),
      pgv.ui_row(
        pgv.ui_text(pgv.t('project.col_client') || ': ' || v_client),
        pgv.ui_badge(v_statut),
        pgv.ui_text(pgv.t('project.col_avancement') || ': ' || v_avancement || ' %')
      ),
      pgv.ui_row(
        pgv.ui_text(pgv.t('project.field_adresse') || ': ' || v_adresse),
        pgv.ui_text(pgv.t('project.col_devis') || ': ' || v_devis)
      ),
      pgv.ui_row(
        pgv.ui_text(pgv.t('project.field_date_debut') || ': ' || v_debut),
        pgv.ui_text(pgv.t('project.field_date_fin_prevue') || ': ' || v_fin)
      ),
      pgv.ui_heading(pgv.t('project.tab_notes'), 3),
      pgv.ui_text(v_notes)
    )
  );
END;
$function$;
COMMENT ON FUNCTION project.chantier_ui(text) IS 'SDUI view: chantier list with datasource table + detail with structured info sections';

CREATE OR REPLACE FUNCTION project.chantier_update(p_row project.chantier)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_result jsonb;
BEGIN
  UPDATE project.chantier SET
    client_id = COALESCE(p_row.client_id, client_id),
    devis_id = COALESCE(p_row.devis_id, devis_id),
    objet = COALESCE(NULLIF(p_row.objet, ''), objet),
    adresse = COALESCE(p_row.adresse, adresse),
    date_debut = COALESCE(p_row.date_debut, date_debut),
    date_fin_prevue = COALESCE(p_row.date_fin_prevue, date_fin_prevue),
    notes = COALESCE(p_row.notes, notes),
    updated_at = now()
  WHERE id = p_row.id AND tenant_id = current_setting('app.tenant_id', true)
  RETURNING to_jsonb(project.chantier.*) INTO v_result;

  RETURN v_result;
END;
$function$;
COMMENT ON FUNCTION project.chantier_update(project.chantier) IS 'Partial update chantier by id — COALESCE preserves unset fields';

