CREATE OR REPLACE FUNCTION project.nav_items()
 RETURNS jsonb
 LANGUAGE sql
 STABLE
AS $function$
  SELECT jsonb_build_array(
    jsonb_build_object('href', '/', 'label', pgv.t('project.nav_dashboard'), 'icon', 'home'),
    jsonb_build_object('href', '/chantiers', 'label', pgv.t('project.nav_projets'), 'icon', 'briefcase', 'entity', 'chantier', 'uri', 'project://chantier'),
    jsonb_build_object('href', '/planning', 'label', pgv.t('project.nav_planning'), 'icon', 'calendar')
  );
$function$;
COMMENT ON FUNCTION project.nav_items() IS 'Navigation items for Project module';

CREATE OR REPLACE FUNCTION project.post_affectation_ajouter(p_chantier_id integer, p_nom_intervenant text, p_role text DEFAULT ''::text, p_heures_prevues numeric DEFAULT NULL::numeric)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_statut text;
BEGIN
  SELECT statut INTO v_statut FROM project.chantier WHERE id = p_chantier_id;
  IF v_statut = 'clos' THEN
    RAISE EXCEPTION '%', pgv.t('project.err_projet_clos_affectation');
  END IF;

  INSERT INTO project.affectation (chantier_id, nom_intervenant, role, heures_prevues)
  VALUES (p_chantier_id, trim(p_nom_intervenant), trim(p_role), p_heures_prevues);

  RETURN pgv.toast(pgv.t('project.toast_intervenant_ajoute'))
    || pgv.redirect(pgv.call_ref('get_chantier', jsonb_build_object('p_id', p_chantier_id)));
END;
$function$;
COMMENT ON FUNCTION project.post_affectation_ajouter(integer,text,text,numeric) IS 'Ajouter un intervenant a un projet';

CREATE OR REPLACE FUNCTION project.post_affectation_supprimer(p_id integer)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_chantier_id int;
  v_statut text;
BEGIN
  SELECT a.chantier_id, c.statut INTO v_chantier_id, v_statut
    FROM project.affectation a
    JOIN project.chantier c ON c.id = a.chantier_id
   WHERE a.id = p_id;

  IF v_statut = 'clos' THEN
    RAISE EXCEPTION '%', pgv.t('project.err_projet_clos_modification');
  END IF;

  DELETE FROM project.affectation WHERE id = p_id;

  RETURN pgv.toast(pgv.t('project.toast_affectation_supprimee'))
    || pgv.redirect(pgv.call_ref('get_chantier', jsonb_build_object('p_id', v_chantier_id)));
END;
$function$;
COMMENT ON FUNCTION project.post_affectation_supprimer(integer) IS 'Supprimer une affectation';

CREATE OR REPLACE FUNCTION project.post_chantier_clore(p_id integer)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  UPDATE project.chantier
     SET statut = 'clos',
         date_fin_reelle = COALESCE(date_fin_reelle, CURRENT_DATE),
         updated_at = now()
   WHERE id = p_id AND statut = 'reception';
  IF NOT FOUND THEN
    RAISE EXCEPTION '%', pgv.t('project.err_pas_reception');
  END IF;
  RETURN pgv.toast(pgv.t('project.toast_clos'))
    || pgv.redirect(pgv.call_ref('get_chantier', jsonb_build_object('p_id', p_id)));
END;
$function$;
COMMENT ON FUNCTION project.post_chantier_clore(integer) IS 'Transition reception -> clos';

CREATE OR REPLACE FUNCTION project.post_chantier_demarrer(p_id integer)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  UPDATE project.chantier
     SET statut = 'execution',
         date_debut = COALESCE(date_debut, CURRENT_DATE),
         updated_at = now()
   WHERE id = p_id AND statut = 'preparation';
  IF NOT FOUND THEN
    RAISE EXCEPTION '%', pgv.t('project.err_pas_preparation');
  END IF;
  RETURN pgv.toast(pgv.t('project.toast_demarre'))
    || pgv.redirect(pgv.call_ref('get_chantier', jsonb_build_object('p_id', p_id)));
END;
$function$;
COMMENT ON FUNCTION project.post_chantier_demarrer(integer) IS 'Transition preparation -> execution';

CREATE OR REPLACE FUNCTION project.post_chantier_reception(p_id integer)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  UPDATE project.chantier
     SET statut = 'reception', updated_at = now()
   WHERE id = p_id AND statut = 'execution';
  IF NOT FOUND THEN
    RAISE EXCEPTION '%', pgv.t('project.err_pas_en_cours');
  END IF;
  RETURN pgv.toast(pgv.t('project.toast_reception'))
    || pgv.redirect(pgv.call_ref('get_chantier', jsonb_build_object('p_id', p_id)));
END;
$function$;
COMMENT ON FUNCTION project.post_chantier_reception(integer) IS 'Transition execution -> reception';

CREATE OR REPLACE FUNCTION project.post_chantier_save(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_id int;
  v_numero text;
BEGIN
  IF p_data->>'id' IS NOT NULL THEN
    v_id := (p_data->>'id')::int;
    IF NOT EXISTS (SELECT 1 FROM project.chantier WHERE id = v_id AND statut IN ('preparation','execution')) THEN
      RAISE EXCEPTION '%', pgv.t('project.err_seuls_modifiables');
    END IF;
    UPDATE project.chantier SET
      client_id = (p_data->>'client_id')::int,
      devis_id = NULLIF(p_data->>'devis_id', '')::int,
      objet = p_data->>'objet',
      adresse = coalesce(p_data->>'adresse', ''),
      date_debut = NULLIF(p_data->>'date_debut', '')::date,
      date_fin_prevue = NULLIF(p_data->>'date_fin_prevue', '')::date,
      notes = coalesce(p_data->>'notes', ''),
      updated_at = now()
    WHERE id = v_id;
  ELSE
    v_numero := project._next_numero();
    INSERT INTO project.chantier (numero, client_id, devis_id, objet, adresse, date_debut, date_fin_prevue, notes)
    VALUES (
      v_numero,
      (p_data->>'client_id')::int,
      NULLIF(p_data->>'devis_id', '')::int,
      p_data->>'objet',
      coalesce(p_data->>'adresse', ''),
      NULLIF(p_data->>'date_debut', '')::date,
      NULLIF(p_data->>'date_fin_prevue', '')::date,
      coalesce(p_data->>'notes', '')
    ) RETURNING id INTO v_id;
  END IF;

  RETURN pgv.toast(pgv.t('project.toast_enregistre'))
    || pgv.redirect(pgv.call_ref('get_chantier', jsonb_build_object('p_id', v_id)));
END;
$function$;
COMMENT ON FUNCTION project.post_chantier_save(jsonb) IS 'Créer ou modifier un projet';

CREATE OR REPLACE FUNCTION project.post_chantier_supprimer(p_id integer)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  IF NOT EXISTS (SELECT 1 FROM project.chantier WHERE id = p_id AND statut = 'preparation') THEN
    RAISE EXCEPTION '%', pgv.t('project.err_seuls_supprimables');
  END IF;
  DELETE FROM project.chantier WHERE id = p_id;
  RETURN pgv.toast(pgv.t('project.toast_supprime'))
    || pgv.redirect(pgv.call_ref('get_chantiers'));
END;
$function$;
COMMENT ON FUNCTION project.post_chantier_supprimer(integer) IS 'Supprimer un projet en preparation';

CREATE OR REPLACE FUNCTION project.post_jalon_ajouter(p_chantier_id integer, p_label text)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_order int;
BEGIN
  IF NOT EXISTS (SELECT 1 FROM project.chantier WHERE id = p_chantier_id AND statut IN ('preparation','execution')) THEN
    RAISE EXCEPTION '%', pgv.t('project.err_non_modifiable');
  END IF;
  SELECT COALESCE(MAX(sort_order), 0) + 1 INTO v_order
    FROM project.jalon WHERE chantier_id = p_chantier_id;
  INSERT INTO project.jalon (chantier_id, sort_order, label)
  VALUES (p_chantier_id, v_order, p_label);
  RETURN pgv.toast(pgv.t('project.toast_jalon_ajoute'))
    || pgv.redirect(pgv.call_ref('get_chantier', jsonb_build_object('p_id', p_chantier_id)));
END;
$function$;
COMMENT ON FUNCTION project.post_jalon_ajouter(integer,text) IS 'Ajouter un jalon a un projet';

CREATE OR REPLACE FUNCTION project.post_jalon_avancer(p_id integer, p_pct numeric)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_chantier_id int;
BEGIN
  SELECT j.chantier_id INTO v_chantier_id
    FROM project.jalon j
    JOIN project.chantier c ON c.id = j.chantier_id
   WHERE j.id = p_id AND c.statut IN ('preparation','execution');
  IF NOT FOUND THEN
    RAISE EXCEPTION '%', pgv.t('project.err_jalon_non_modifiable');
  END IF;
  UPDATE project.jalon SET
    pct_avancement = LEAST(GREATEST(p_pct, 0), 100),
    statut = CASE WHEN p_pct >= 100 THEN 'valide' WHEN p_pct > 0 THEN 'en_cours' ELSE 'a_faire' END
  WHERE id = p_id;
  RETURN pgv.toast(pgv.t('project.toast_avancement_maj'))
    || pgv.redirect(pgv.call_ref('get_chantier', jsonb_build_object('p_id', v_chantier_id)));
END;
$function$;
COMMENT ON FUNCTION project.post_jalon_avancer(integer,numeric) IS 'Mettre a jour le pourcentage d''avancement d''un jalon';

CREATE OR REPLACE FUNCTION project.post_jalon_supprimer(p_id integer)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_chantier_id int;
BEGIN
  SELECT j.chantier_id INTO v_chantier_id
    FROM project.jalon j
    JOIN project.chantier c ON c.id = j.chantier_id
   WHERE j.id = p_id AND c.statut IN ('preparation','execution');
  IF NOT FOUND THEN
    RAISE EXCEPTION '%', pgv.t('project.err_jalon_non_modifiable');
  END IF;
  DELETE FROM project.jalon WHERE id = p_id;
  RETURN pgv.toast(pgv.t('project.toast_jalon_supprime'))
    || pgv.redirect(pgv.call_ref('get_chantier', jsonb_build_object('p_id', v_chantier_id)));
END;
$function$;
COMMENT ON FUNCTION project.post_jalon_supprimer(integer) IS 'Supprimer un jalon';

CREATE OR REPLACE FUNCTION project.post_jalon_valider(p_id integer)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_chantier_id int;
  v_sort int;
  v_prev_not_valide boolean;
BEGIN
  SELECT j.chantier_id, j.sort_order INTO v_chantier_id, v_sort
    FROM project.jalon j
    JOIN project.chantier c ON c.id = j.chantier_id
   WHERE j.id = p_id AND j.statut <> 'valide' AND c.statut IN ('preparation','execution');
  IF NOT FOUND THEN
    RAISE EXCEPTION '%', pgv.t('project.err_jalon_deja_valide');
  END IF;

  SELECT EXISTS (
    SELECT 1 FROM project.jalon
     WHERE chantier_id = v_chantier_id AND sort_order < v_sort AND statut <> 'valide'
  ) INTO v_prev_not_valide;

  IF v_prev_not_valide THEN
    RAISE EXCEPTION '%', pgv.t('project.err_jalons_precedents');
  END IF;

  UPDATE project.jalon SET
    statut = 'valide',
    pct_avancement = 100,
    date_reelle = CURRENT_DATE
  WHERE id = p_id;

  RETURN pgv.toast(pgv.t('project.toast_jalon_valide'))
    || pgv.redirect(pgv.call_ref('get_chantier', jsonb_build_object('p_id', v_chantier_id)));
END;
$function$;
COMMENT ON FUNCTION project.post_jalon_valider(integer) IS 'Valider un jalon (verification ordre sequentiel)';

CREATE OR REPLACE FUNCTION project.post_note_ajouter(p_chantier_id integer, p_contenu text)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  IF NOT EXISTS (SELECT 1 FROM project.chantier WHERE id = p_chantier_id AND statut IN ('preparation','execution')) THEN
    RAISE EXCEPTION '%', pgv.t('project.err_non_modifiable');
  END IF;
  INSERT INTO project.note_chantier (chantier_id, contenu)
  VALUES (p_chantier_id, p_contenu);
  RETURN pgv.toast(pgv.t('project.toast_note_ajoutee'))
    || pgv.redirect(pgv.call_ref('get_chantier', jsonb_build_object('p_id', p_chantier_id)));
END;
$function$;
COMMENT ON FUNCTION project.post_note_ajouter(integer,text) IS 'Ajouter une note de projet';

CREATE OR REPLACE FUNCTION project.post_note_supprimer(p_id integer)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_chantier_id int;
BEGIN
  SELECT n.chantier_id INTO v_chantier_id
    FROM project.note_chantier n
    JOIN project.chantier c ON c.id = n.chantier_id
   WHERE n.id = p_id AND c.statut IN ('preparation','execution');
  IF NOT FOUND THEN
    RAISE EXCEPTION '%', pgv.t('project.err_note_non_modifiable');
  END IF;
  DELETE FROM project.note_chantier WHERE id = p_id;
  RETURN pgv.toast(pgv.t('project.toast_note_supprimee'))
    || pgv.redirect(pgv.call_ref('get_chantier', jsonb_build_object('p_id', v_chantier_id)));
END;
$function$;
COMMENT ON FUNCTION project.post_note_supprimer(integer) IS 'Supprimer une note de projet';

CREATE OR REPLACE FUNCTION project.post_pointage_ajouter(p_chantier_id integer, p_heures numeric, p_description text DEFAULT ''::text, p_date date DEFAULT CURRENT_DATE)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  IF NOT EXISTS (SELECT 1 FROM project.chantier WHERE id = p_chantier_id AND statut IN ('preparation','execution')) THEN
    RAISE EXCEPTION '%', pgv.t('project.err_non_modifiable');
  END IF;
  INSERT INTO project.pointage (chantier_id, date_pointage, heures, description)
  VALUES (p_chantier_id, p_date, p_heures, COALESCE(p_description, ''));
  RETURN pgv.toast(pgv.t('project.toast_pointage_ajoute'))
    || pgv.redirect(pgv.call_ref('get_chantier', jsonb_build_object('p_id', p_chantier_id)));
END;
$function$;
COMMENT ON FUNCTION project.post_pointage_ajouter(integer,numeric,text,date) IS 'Ajouter un pointage d''heures';

CREATE OR REPLACE FUNCTION project.post_pointage_supprimer(p_id integer)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_chantier_id int;
BEGIN
  SELECT p.chantier_id INTO v_chantier_id
    FROM project.pointage p
    JOIN project.chantier c ON c.id = p.chantier_id
   WHERE p.id = p_id AND c.statut IN ('preparation','execution');
  IF NOT FOUND THEN
    RAISE EXCEPTION '%', pgv.t('project.err_pointage_non_modifiable');
  END IF;
  DELETE FROM project.pointage WHERE id = p_id;
  RETURN pgv.toast(pgv.t('project.toast_pointage_supprime'))
    || pgv.redirect(pgv.call_ref('get_chantier', jsonb_build_object('p_id', v_chantier_id)));
END;
$function$;
COMMENT ON FUNCTION project.post_pointage_supprimer(integer) IS 'Supprimer un pointage';

